PREFIX bd: <http://www.bigdata.com/rdf#>
SELECT ?numRaces
WHERE {
  ?season a wd:Q3866634 ;
          wdt:P1081 wd:Q75442 ;
          wdt:P4989 ?numRaces ;
          wdt:P585 ?date .
  FILTER (bd:year(?date) >= 2015)
}
ORDER BY ASC(?numRaces)
LIMIT 1
OFFSET 1

